package travelcare_agent.evaluation.dto; import travelcare_agent.evaluation.entity.EvaluationRun; public record EvaluationRunResponse(Long id,Long datasetId,Integer datasetVersion,Long baselineRunId,String providerMode,String promptStubVersion,String status,Integer totalCount,Integer passedCount,Integer failedCount,Integer errorCount,Integer skippedCount,String regressionStatus,Integer regressionCount,Integer improvedCount,Integer newCaseCount,Integer missingCaseCount,String summaryJson){public static EvaluationRunResponse from(EvaluationRun v){return new EvaluationRunResponse(v.getId(),v.getDatasetId(),v.getDatasetVersion(),v.getBaselineRunId(),v.getProviderMode(),v.getPromptStubVersion(),v.getStatus(),v.getTotalCount(),v.getPassedCount(),v.getFailedCount(),v.getErrorCount(),v.getSkippedCount(),v.getRegressionStatus(),v.getRegressionCount(),v.getImprovedCount(),v.getNewCaseCount(),v.getMissingCaseCount(),v.getSummaryJson());}}
